import { Grid, Paper } from "@mui/material"
import { SectionTitle } from "../components/formElements/SectionTitle"
import { ReactMarkdown } from "react-markdown/lib/react-markdown"
import InformationMD from '../markdowns/Information.md'
import AboutMD from '../markdowns/About.md'
import { useEffect, useState } from "react"
import remarkGfm from "remark-gfm";
import rehypeSlug from 'rehype-slug'
import rehypeAutolinkHeadings from 'rehype-autolink-headings'
import { toSnakeCase } from "../utils/StringManipulation"

const informationContainerStyles = {
    backgroundColor: 'aliceblue',
    color: 'rgba(0, 0, 0, 0.7)',
    fontSize: '0.9em'
}

export const InformationContainer = () => {

    const [infoContent, setInfoContent] = useState('');
    const [aboutContent, setAboutContent] = useState('');

    const readMarkdownToState = (sourcePath: string, setter: any) => {
        fetch(sourcePath)
            .then((response) => response.text())
            .then((text) => {
                setter(text);
            });
    }

    useEffect(() => {
        readMarkdownToState(AboutMD, setAboutContent)
        readMarkdownToState(InformationMD, setInfoContent)
    }, []);

    // const customizeTOC = (toc: any): any => {
    //     toc.tagName = "ul"
    //     return toc
    // }

    const mdSection = (title: string, content: string) => {
        return <>
            <Grid item xs={12} id={toSnakeCase(title)}>
                <SectionTitle title={title} />
            </Grid>
            <ReactMarkdown remarkPlugins={[remarkGfm]} rehypePlugins={[rehypeSlug, rehypeAutolinkHeadings]}>
                {content}
            </ReactMarkdown>
        </>
    }

    return (
        <Paper elevation={4} sx={{ p: 4, pt: 0, mt: 4 }} style={informationContainerStyles}>
            {mdSection("About", aboutContent)}
            {mdSection("Useful References", infoContent)}
        </Paper>
    )
}