import { Table, TableHead, TableCell, TableBody, TableRow, ToggleButton, Grid } from "@mui/material"
import { useDispatch, useSelector } from "react-redux"
import { addInvestment, removeInvestment, updateInvestment } from "../store/rentAndInvestment"
import { SalaryComponentInput } from "./formElements/SalaryComponentInput"
import { SectionTitle } from "./formElements/SectionTitle"
import { SectionNotApplicable } from "./formElements/SectionNotApplicable"
import { CalculatedLimitedDeductibleComponent, LimitedDeductibleComponent, listInvestmentsForTaxRegimeId } from "@harshit-kushwaha/tax-calculator-lib"
import { useState } from "react"
import { Investment } from "../types/Investment.type"
import { SectionMessage } from "./formElements/SectionMessage"
import { CustomInfoIcon } from "./formElements/InfoIcon"

export const Investments = () => {
    const titleIcon = <CustomInfoIcon link="#investment-categories" />
    const title = <SectionTitle title={<>Investments {titleIcon} </>} />

    const investments: any[] = useSelector<any, any[]>(state => state.rentAndInvestments.investments)
    const { selectedRegime } = useSelector<any, any>(state => state.taxRegime)

    const dispatch = useDispatch()

    const applicableDeductibles = listInvestmentsForTaxRegimeId(selectedRegime)

    const [selectedInvestments, setSelectedInvestments] = useState<string[]>(
        investments.map((investment: any) => investment.name)
    )

    const areDeductiblesApplicable = (): boolean => (applicableDeductibles.length > 0)


    const handleInvestmentToggle = (event: any) => {
        const toggledInvestmentName = event.target.value
        const existingInvestments = investments.map((investment: Investment) => investment.name)

        if (existingInvestments.includes(toggledInvestmentName)) {
            selectedInvestments.splice(toggledInvestmentName, 1)
            dispatch(removeInvestment(toggledInvestmentName))
        } else {
            const currentInvestments = [...selectedInvestments]
            currentInvestments.push(toggledInvestmentName)
            dispatch(addInvestment({
                name: toggledInvestmentName,
                value: 0
            }))
            setSelectedInvestments(currentInvestments)

        }
    }

    const toggleInvestments = () => {
        return (
            <Grid xs={12} container>
                {
                    applicableDeductibles.map(deductible => (
                        <Grid item xs={6} sm={3}>
                            <ToggleButton selected={selectedInvestments.includes(deductible.name)} size="small" value={deductible.name} fullWidth style={{ minHeight: '100%' }} onClick={handleInvestmentToggle}>
                                {deductible.displayName}
                            </ToggleButton>
                        </Grid>
                    ))
                }
            </Grid>
        )
    }

    const handleInvestmentInputChange = (investmentName: string, investmentValue: number): any => updateInvestment(
        { name: investmentName, value: investmentValue }
    )

    const getMaxValueForInvestment = (investmentName: string): number => {
        return (applicableDeductibles.find(dedcutible => dedcutible.name === investmentName) as LimitedDeductibleComponent)['limit'] ?? 0
    }

    const getMaxValueHintForInvestment = (investmentName: string): string => {
        return (applicableDeductibles.find(dedcutible => dedcutible.name === investmentName) as CalculatedLimitedDeductibleComponent)['limitHint']
    }

    const listInvestments = () => {
        const addedInvestments = investments.map((investment: any) => (
            <TableRow>
                <TableCell>{investment.name}</TableCell>
                {/* TODO: Display PF amount already set as 80C  */}
                <TableCell><SalaryComponentInput value={investment.value} onInputChange={(input: number) => handleInvestmentInputChange(investment.name, input)} maxValue={getMaxValueForInvestment(investment.name)} maxValueHint={getMaxValueHintForInvestment(investment.name)} /></TableCell>
            </TableRow>
        )
        )

        return (
            <Table size="small" stickyHeader>
                <TableHead>
                    <TableCell>Investment</TableCell>
                    <TableCell>Amount (Yearly)</TableCell>
                </TableHead>
                <TableBody>
                    {addedInvestments}
                </TableBody>
            </Table>
        )
    }

    const renderInvestmentsTable = () => {
        return investments.length > 0
            ? listInvestments()
            : <SectionMessage message="Select investments from above options to add" />
    }

    const investmentsInput = () => {
        return renderInvestmentsTable()
    }

    const sectionNA = () => (<SectionNotApplicable sectionName="Investment" />)

    const sectionInvestments = () => (
        <>
            {toggleInvestments()}
            {investmentsInput()}

        </>
    )

    return (<>
        {title}
        {
            areDeductiblesApplicable()
                ? sectionInvestments()
                : sectionNA()
        }
    </>
    )

}