import { Grid, Paper, Typography } from "@mui/material"

type PageTitleProps = {
    title: string
}

const pageTitleStyle = {
    'text-align': 'center',
    display: 'block',
    'text-transform': 'uppercase',
}

const background = {
    backgroundColor: '#f5f5f5',
}


export const PageTitle = (props: PageTitleProps) => {
    const { title } = props

    return <Grid container xs={12} sx={{ mb: 2 }}>
        <Grid item xs={12} sx={background}>
            <Paper sx={{ p: 2 }}>
                <Typography style={pageTitleStyle} variant={'h6'}> {title} </Typography>
            </Paper>
        </Grid>
    </Grid>
}