import { createSlice } from "@reduxjs/toolkit";

const initialState = {
    basic: 0,
    hra: 0,
    otherAllowances: 0,
    providendFund: 0,
    gratuity: 0,
}

// Reducer
const slice = createSlice({
    name: 'salaryBreakup',
    initialState,
    reducers: {
        setBasic: (state, action) => {
            state.basic = action.payload;
        },
        setHra: (state, action) => {
            state.hra = action.payload;
        },
        setAllowances: (state, action) => {
            state.otherAllowances = action.payload;
        },
        setProvidendFund: (state, action) => {
            state.providendFund = action.payload;
        },
        setGratuity: (state, action) => {
            state.gratuity = action.payload;
        },
        resetSalaryBreakup: () => initialState
    },
});

export default slice.reducer

// Actions
export const { setBasic, setHra, setAllowances, setProvidendFund, setGratuity, resetSalaryBreakup } = slice.actions