import { RadioGroup, Grid, FormControlLabel, Radio } from "@mui/material"
import { useDispatch, useSelector } from "react-redux"
import { listTaxRegimesForYearId } from "@harshit-kushwaha/tax-calculator-lib"
import { selectTaxRegime } from "../store/taxRegime"
import { useEffect } from "react"
import { SectionTitle } from "./formElements/SectionTitle"

export const TaxRegimeSelector = () => {

    const selectedRegime = useSelector<any, string>(state => state.taxRegime.selectedRegime)
    const selectedFinancialYear = useSelector<any, string>(state => state.financialYear.selectedYear)
    const regimes = listTaxRegimesForYearId(selectedFinancialYear)

    const dispatch = useDispatch()

    const defaultRegime = selectedRegime ?? regimes[0]?.id

    useEffect(() => {
        dispatch(selectTaxRegime(defaultRegime))
    }, [defaultRegime, dispatch])

    const handleTaxRegimeSelection = (event: any) => {
        dispatch(selectTaxRegime(event.target.value))
    }


    const renderRegimes = (regimes: any[]) => (
        <Grid item xs={12} sx={{ pl: 2, pr: 2 }}>
            <RadioGroup
                row
                name="radio-buttons-group"
                value={selectedRegime}
                onChange={handleTaxRegimeSelection}
                defaultValue={defaultRegime}
            >
                {
                    regimes.map(regime => (
                        <Grid item md={6} xs={12}>
                            <FormControlLabel value={regime.id} control={<Radio />} label={regime.name} />
                        </Grid>
                    ))
                }

            </RadioGroup>
        </Grid>
    )

    const isEmpty = () => {
        return !(selectedFinancialYear && regimes.length)
    }

    return (<>
        {isEmpty()
            ? <></>
            : <Grid container xs={12}>
                <SectionTitle title="Tax Regime" />
                {renderRegimes(regimes)}
            </Grid>
        }
    </>)
}


