import { Chart } from "react-google-charts";

export const options = {
  title: "Monthly Salary Breakup",
  is3D: true,
  colors: ['#5c6bc0', '#29b6f6', '#26a69a', '#9ccc65', '#ffee58'],
};

type PieChartProps = {
  data: any[]
}

export const PieChart = (props: PieChartProps) => {

  const { data } = { ...props }

  return (
    <Chart
      chartType="PieChart"
      data={data}
      options={options}
      width={"100%"}
      height={"400px"}
    />
  );
}
