import { Grid, Table, TableBody, TableCell, TableHead, TableRow } from "@mui/material"
import { SalaryComponentInput } from "./formElements/SalaryComponentInput"
import { SalaryComponentOutput } from "./formElements/SalaryComponentOutput"
import { setAllowances, setBasic, setProvidendFund, setGratuity, setHra } from "../store/salary"
import { useDispatch, useSelector } from "react-redux"
import { useEffect } from "react"
import { setNextDisableForStep } from "../store/navigation"
import { SectionTitle } from "./formElements/SectionTitle"

export const SalaryBreakUp = () => {

    const { basic, hra, otherAllowances, providendFund, gratuity } = useSelector<any, any>(state => state.salaryBreakup)

    const componentsTotal = (): number => (
        basic + hra + otherAllowances + providendFund + gratuity
    )

    const dispatch = useDispatch()

    useEffect(() => {
        if (componentsTotal() === 0) {
            dispatch(setNextDisableForStep(1, true))
        } else {
            dispatch(setNextDisableForStep(1, false))
        }
    })

    const formInputs = () => {
        return (
            <>
                <Table size="small" stickyHeader>
                    <TableHead>
                        <TableRow>
                            <TableCell>Salary Component</TableCell>
                            <TableCell>Amount (Annual)</TableCell>
                        </TableRow>
                    </TableHead>
                    <TableBody>
                        <TableRow>
                            <TableCell>Basic</TableCell>
                            <TableCell><SalaryComponentInput value={basic} onInputChange={setBasic} /></TableCell>
                        </TableRow>
                        <TableRow>
                            <TableCell>Hra</TableCell>
                            <TableCell><SalaryComponentInput value={hra} onInputChange={setHra} /></TableCell>
                        </TableRow>
                        <TableRow>
                            <TableCell>Other Allowances</TableCell>
                            <TableCell><SalaryComponentInput value={otherAllowances} onInputChange={setAllowances} /></TableCell>
                        </TableRow>
                        <TableRow>
                            <TableCell>Employer's PF contribution</TableCell>
                            <TableCell><SalaryComponentInput value={providendFund} onInputChange={setProvidendFund} /></TableCell>
                        </TableRow>
                        <TableRow>
                            <TableCell>Gratuity</TableCell>
                            <TableCell><SalaryComponentInput value={gratuity} onInputChange={setGratuity} /></TableCell>
                        </TableRow>
                        <TableRow>
                            <TableCell>Total CTC</TableCell>
                            <TableCell><SalaryComponentOutput outputValue={componentsTotal()} /></TableCell>
                        </TableRow>
                    </TableBody>
                </Table>
            </>
        )
    }

    return (
        <>
            <Grid container xs={12}>
                <SectionTitle title="Annual CTC Breakup" />
                {formInputs()}
            </Grid>
        </>
    )
}