import { Grid, MenuItem, Select } from "@mui/material"
import { useFinancialYears } from "../hooks/useFinancialYears"
import { FinancialYear } from "../types/financialYear.type"
import { useSelector, useDispatch } from "react-redux";
import { selectFinancialYear } from "../store/financialYear";
import { useEffect } from "react";
import { SectionTitle } from "./formElements/SectionTitle";

export const FinancialYearSelector = () => {

    const { financialYearOptions, defaultFinancialYear } = useFinancialYears()
    const selectedFinancialYear = useSelector<any>(state => state.financialYear.selectedYear)

    const dispatch = useDispatch()

    useEffect(() => {
        dispatch(selectFinancialYear(defaultFinancialYear))
    }, [defaultFinancialYear, dispatch])

    const handleFinancialYearSelect = (event: any) => {
        dispatch(selectFinancialYear(event.target.value))
    }

    const financialYearSelector = () => {
        return (
            <Grid item xs={12}>
                <SectionTitle title={"Financial Year"} />
                <Grid item xs={12} sx={{ pl: 2, pr: 2 }}>
                    <Select
                        labelId="demo-simple-select-label"
                        id="demo-simple-select"
                        fullWidth
                        defaultValue={defaultFinancialYear}
                        value={selectedFinancialYear}
                        onChange={handleFinancialYearSelect}
                        type="standard"
                        size="small"
                    >
                        {financialYearOptions?.map((year: FinancialYear) => (
                            <MenuItem value={year.id}>{year.value}</MenuItem>
                        ))}
                    </Select>
                </Grid>
            </Grid>
        )
    }

    return (<Grid container xs={12}>
        {financialYearSelector()}
    </Grid>)
}
