import { Grid, Table, TableBody, TableCell, TableRow } from "@mui/material"
import { SalaryBreakup } from "../types/SalaryBreakup.type"
import { NonTaxableExpense, calculateNetIncome, Deduction, Investment } from "@harshit-kushwaha/tax-calculator-lib"
import { useSelector } from "react-redux"
import { SalaryComponentOutput } from "./formElements/SalaryComponentOutput"
import { SectionTitle } from "./formElements/SectionTitle"
import { Investment as SalaryInvestment } from "../types/Investment.type"
import { SectionMessage } from "./formElements/SectionMessage"
import { PieChart } from "./DoughnutChart"
import { useEffect } from "react"

export const NetSalary = () => {

    useEffect(() => {
        // 👇️ scroll to top on page load
        window.scrollTo({ top: 0, left: 0, behavior: 'smooth' });
    }, []);

    const salaryBreakup = useSelector<any, SalaryBreakup>(state => state.salaryBreakup)
    const taxRegimeId = useSelector<any, string>(state => state.taxRegime.selectedRegime)
    const investments: SalaryInvestment[] = useSelector<any, SalaryInvestment[]>(state => state.rentAndInvestments.investments)
    const monthlyProfessionalTax = useSelector<any, number>(state => state.professionalTax.monthlyProfessionalTax)
    const monthlyRent: number = useSelector<any, number>(state => state.rentAndInvestments.monthlyRent)
    const isMetroCity: boolean = useSelector<any, boolean>(state => state.rentAndInvestments.metroCity)

    if (isSalaryBreakupZero(salaryBreakup) || !taxRegimeId) {
        return <></>
    }

    const annualProfessionalTax = monthlyProfessionalTax * 12

    const nonTaxableExpenses: NonTaxableExpense = nonTaxableExpense(salaryBreakup.providendFund, investments, monthlyRent, isMetroCity)

    const income = calculateNetIncome(
        taxRegimeId,
        { ...salaryBreakup, providendFund: { amount: salaryBreakup.providendFund }, professionalTax: annualProfessionalTax },
        nonTaxableExpenses
    )

    const isRebateApplicable = income.rebateAmount > 0

    const annualNetSalary = Math.round(income.netIncome)
    const monthlyNetSalary = Math.round(income.netIncome / 12)
    const taxableIncome = Math.round(income.taxableIncome)
    const incomeTax = Math.round(income.incomeTax)

    const effectiveAnnualNetSalary = annualNetSalary + incomeTax
    const effectiveMonthlyNetSalary = Math.round(effectiveAnnualNetSalary / 12)
    const effectiveTaxableIncome = 0
    const effectiveIncomeTax = 0

    const salaryDeductions = income.nonTaxSalaryDeductions

    const tableDivider = () => (
        <TableRow sx={{backgroundColor: 'ghostwhite'}}>
            <TableCell></TableCell>
            <TableCell></TableCell>
        </TableRow>
    )

    const effectiveRows = () => {
        return (<>
            {tableDivider()}
            <TableRow sx={{ backgroundColor: '#fff9c4' }}>
                <TableCell>Effective Salary In Hand (p.m.)</TableCell>
                <TableCell><SalaryComponentOutput outputValue={effectiveMonthlyNetSalary} strikedValue={monthlyNetSalary} /></TableCell>
            </TableRow>
            <TableRow sx={{ backgroundColor: '#fff9c4' }}>
                <TableCell>Effective Total Net Salary (p.a.)</TableCell>
                <TableCell><SalaryComponentOutput outputValue={effectiveAnnualNetSalary} strikedValue={annualNetSalary} /></TableCell>
            </TableRow>
            <TableRow sx={{ backgroundColor: '#fff9c4' }}>
                <TableCell>Effective Total Taxable Income</TableCell>
                <TableCell><SalaryComponentOutput outputValue={effectiveTaxableIncome} strikedValue={taxableIncome} /></TableCell>
            </TableRow>
            <TableRow sx={{ backgroundColor: '#fff9c4' }}>
                <TableCell>Effective Total Tax Payable</TableCell>
                <TableCell><SalaryComponentOutput outputValue={effectiveIncomeTax} strikedValue={incomeTax} /></TableCell>
            </TableRow>
        </>)
    }

    const chartData = [
        ["Component", "Amount (p.m.)"],
        ["Net (In Hand) Salary", isRebateApplicable ? effectiveMonthlyNetSalary : monthlyNetSalary],
        ["Income Tax", Math.round((isRebateApplicable ? effectiveIncomeTax : incomeTax) / 12)],
        ["Professional Tax", Math.round(income.professionalTax / 12)]
    ]

    salaryDeductions.forEach(deduction => chartData.push([deduction.displayName, Math.round(deduction.amount / 12)]))

    const otherSalaryDeductions = () => {
        return salaryDeductions.map(salaryDeduction => (
            <TableRow>
                <TableCell>{salaryDeduction.displayName} (p.m.)</TableCell>
                <TableCell><SalaryComponentOutput outputValue={Math.round(salaryDeduction.amount/12)} /></TableCell>
            </TableRow>
        ))
    }

    return (
        <Grid container xs={12}>
            <SectionTitle title="Net (In Hand) Salary" />
            <Grid item xs={12} md={6}>
                <PieChart data={chartData} />
            </Grid>
            <Grid item xs={12} md={6}>
                {isRebateApplicable && <SectionMessage info message="Hurray! You are elligible for a tax rebate." />}
                <Table size="small" stickyHeader>
                    <TableBody>
                        <TableRow>
                            <TableCell>Salary In Hand (p.m.)</TableCell>
                            <TableCell><SalaryComponentOutput outputValue={monthlyNetSalary} /></TableCell>
                        </TableRow>
                        {tableDivider()}
                        <TableRow>
                            <TableCell>Income Tax (p.m.)</TableCell>
                            <TableCell><SalaryComponentOutput outputValue={Math.round(incomeTax / 12)} /></TableCell>
                        </TableRow>
                        <TableRow>
                            <TableCell>Professional Tax (p.m.)</TableCell>
                            <TableCell><SalaryComponentOutput outputValue={Math.round(income.professionalTax / 12)} /></TableCell>
                        </TableRow>
                        {otherSalaryDeductions()}
                        {tableDivider()}
                        <TableRow>
                            <TableCell>Total Net Salary (p.a.)</TableCell>
                            <TableCell><SalaryComponentOutput outputValue={annualNetSalary} /></TableCell>
                        </TableRow>
                        <TableRow>
                            <TableCell>Total Taxable Income</TableCell>
                            <TableCell><SalaryComponentOutput outputValue={taxableIncome} /></TableCell>
                        </TableRow>
                        <TableRow>
                            <TableCell>Total Tax Payable</TableCell>
                            <TableCell><SalaryComponentOutput outputValue={incomeTax} /></TableCell>
                        </TableRow>
                        {
                            isRebateApplicable && effectiveRows()
                        }
                    </TableBody>
                </Table>
            </Grid>
        </Grid>
    )
}

const nonTaxableExpense = (pfAmount: number, investments: SalaryInvestment[], monthlyRent: number, isMetroCity: boolean): NonTaxableExpense => {

    const investment_80c: Investment = {
        name: Deduction.INV_80_C,
        amount: pfAmount
    }

    const otherInvestments: Investment[] = []

    investments.forEach(investment => {
        if (investment.name === Deduction.INV_80_C) {
            investment_80c.amount += investment.value
        } else {
            otherInvestments.push({ name: investment.name, amount: investment.value })
        }
    })

    return {
        investments: [investment_80c, ...otherInvestments],
        rent: monthlyRent > 0
            ? {
                amount: monthlyRent * 12,
                // TODO: ADD THIS IN UI
                isMetro: isMetroCity
            }
            : undefined
    }
}

const isSalaryBreakupZero = (salaryBreakup: any): boolean => {
    const totalAmount = Object.keys(salaryBreakup)
        .map(key => salaryBreakup[key] as number)
        .reduce((total, componentAmount) => total + componentAmount)

    return totalAmount === 0
}