import { FormLabel, Grid, Paper } from "@mui/material"

type SectionTitleProps = {
    title: any
}

const sectionTitleStyle = {
    'text-align': 'center',
    display: 'block',
    fontWeight: '500'
}

const sectionShadow = {
    p: 2,
    backgroundColor: 'rgba(255, 255, 255, 0.0)',
    'box-shadow': '0px 10px 10px -15px #111'
}

export const SectionTitle = (props: SectionTitleProps) => {
    const { title } = props
    return <Grid container xs={12} sx={{ mt:2, mb:2 }}>
        <Grid item xs={12}>
            <Paper elevation={2} sx={sectionShadow}>
                <FormLabel style={sectionTitleStyle}> {title} </FormLabel>
            </Paper>
        </Grid>
    </Grid>
}