import { styled } from '@mui/material/styles';
import { Button, Grid, MobileStepper, Stack, Step, StepConnector, StepIconProps, StepLabel, Stepper, stepConnectorClasses } from "@mui/material"
import CalendarMonthRoundedIcon from '@mui/icons-material/CalendarMonthRounded';
import PieChartRoundedIcon from '@mui/icons-material/PieChartRounded';
import CurrencyRupeeRoundedIcon from '@mui/icons-material/CurrencyRupeeRounded';
import { useState } from 'react';
import { steps } from '../components/config/Step.config';
import NavigateNextRoundedIcon from '@mui/icons-material/NavigateNextRounded';
import NavigateBeforeRoundedIcon from '@mui/icons-material/NavigateBeforeRounded';
import { useDispatch, useSelector } from 'react-redux';
import { resetFinancialYear } from '../store/financialYear';
import { resetTaxRegime } from '../store/taxRegime';
import { resetSalaryBreakup } from '../store/salary';
import { resetNavigation } from '../store/navigation';
import MapsHomeWorkRoundedIcon from '@mui/icons-material/MapsHomeWorkRounded';
import { resetRentAndInvestments } from '../store/rentAndInvestment';
import KeyboardArrowRightRoundedIcon from '@mui/icons-material/KeyboardArrowRightRounded';
import KeyboardArrowLeftRoundedIcon from '@mui/icons-material/KeyboardArrowLeftRounded';
import { PageTitle } from '../components/formElements/PageTitle';
import { resetProfessionalTax } from '../store/professionalTax';
import ReactGA from "react-ga4";

const ColorlibConnector = styled(StepConnector)(({ theme }) => ({
    [`&.${stepConnectorClasses.alternativeLabel}`]: {
        top: 22,
    },
    [`&.${stepConnectorClasses.active}`]: {
        [`& .${stepConnectorClasses.line}`]: {
            // backgroundImage:
            //     'linear-gradient( 95deg,rgb(33, 150, 243) 0%,rgb(25, 118, 210) 50%,rgb(13, 71, 161) 100%)',
            backgroundColor: '#1976D2'
        },
    },
    [`&.${stepConnectorClasses.completed}`]: {
        [`& .${stepConnectorClasses.line}`]: {
            // backgroundImage:
            //     'linear-gradient( 95deg,rgb(33, 150, 243) 0%,rgb(25, 118, 210) 50%,rgb(13, 71, 161) 100%)',
            backgroundColor: '#1976D2'
        },
    },
    [`& .${stepConnectorClasses.line}`]: {
        height: 3,
        border: 0,
        backgroundColor:
            theme.palette.mode === 'dark' ? theme.palette.grey[800] : '#eaeaf0',
        borderRadius: 1,
    },
}));

const ColorlibStepIconRoot = styled('div')<{
    ownerState: { completed?: boolean; active?: boolean };
}>(({ theme, ownerState }) => ({
    backgroundColor: theme.palette.mode === 'dark' ? theme.palette.grey[700] : '#ccc',
    zIndex: 1,
    color: '#fff',
    width: 50,
    height: 50,
    display: 'flex',
    borderRadius: '50%',
    justifyContent: 'center',
    alignItems: 'center',
    ...(ownerState.active && {
        // backgroundImage:
        // 'linear-gradient( 95deg,rgb(33, 150, 243) 0%,rgb(25, 118, 210) 50%,rgb(13, 71, 161) 100%)',
        backgroundColor: '#1976D2',
        // boxShadow: '0 4px 10px 0 rgba(0,0,0,.5)',
        boxShadow: '0px 3px 1px -2px rgba(0,0,0,0.2), 0px 2px 2px 0px rgba(0,0,0,0.14), 0px 1px 5px 0px rgba(0,0,0,0.12);'
    }),
    ...(ownerState.completed && {
        // backgroundImage:
        //     'linear-gradient( 95deg,rgb(33, 150, 243) 0%,rgb(25, 118, 210) 50%,rgb(13, 71, 161) 100%)',
        backgroundColor: '#1976D2',
    }),
}));

function ColorlibStepIcon(props: StepIconProps) {
    const { active, completed, className } = props;

    const icons: { [index: string]: React.ReactElement } = {
        1: <CalendarMonthRoundedIcon />,
        2: <CurrencyRupeeRoundedIcon />,
        3: <MapsHomeWorkRoundedIcon />,
        4: <PieChartRoundedIcon />,
    };

    return (
        <ColorlibStepIconRoot ownerState={{ completed, active }} className={className}>
            {icons[String(props.icon)]}
        </ColorlibStepIconRoot>
    );
}

export default function StepperComponent() {

    const [activeStep, setActiveStep] = useState(0);

    const dispatch = useDispatch()

    const handleNext = () => {
        ReactGA.event({
            action: `next_button_click_to_step_${activeStep + 2}`,
            category: 'engagement',
            label: 'next',
        })
        setActiveStep(prevActiveStep => prevActiveStep + 1);
    };

    const handleBack = () => {
        ReactGA.event({
            action: `back_button_click_to_step_${activeStep}`,
            category: 'engagement',
            label: 'back',
        })
        setActiveStep(prevActiveStep => prevActiveStep - 1);
    };

    const handleReset = () => {
        dispatch(resetFinancialYear())
        dispatch(resetTaxRegime())
        dispatch(resetSalaryBreakup())
        dispatch(resetNavigation())
        dispatch(resetRentAndInvestments())
        dispatch(resetProfessionalTax())
        ReactGA.event({
            action: `reset_button_click_step_${activeStep + 1}`,
            category: 'engagement',
            label: 'reset',
        })
        setActiveStep(0)
    }

    const isNextButtonDisabled = useSelector<any, any>(state => state.navigation.nextDisabled)


    const isNextButtonShown = () => {
        return activeStep < steps.length - 1;
    }

    const isResetButtonShown = () => {
        return activeStep > 0
    }

    const isBackButtonShown = () => {
        return activeStep > 0
    }


    const renderButtons = () => (
        <Grid container xs={12} sx={{ justifyContent: 'flex-end' }} spacing={2} mt={2}>
            <Grid item xs={12} sm={3} md={2}>
                {isBackButtonShown() &&
                    <Button onClick={handleBack} startIcon={<NavigateBeforeRoundedIcon />} fullWidth>
                        Back
                    </Button>}
            </Grid>
            <Grid item xs={12} sm={3} md={2} >
                {isResetButtonShown() &&
                    <Button onClick={handleReset} color={"error"} variant="outlined" fullWidth>
                        Reset
                    </Button>
                }
            </Grid>
            <Grid item xs={12} sm={3} md={2}>
                {isNextButtonShown() &&
                    <Button
                        fullWidth
                        variant="contained"
                        color="primary"
                        onClick={handleNext}
                        endIcon={<NavigateNextRoundedIcon />}
                        disabled={isNextButtonDisabled[activeStep]}
                    >
                        Next
                    </Button>
                }
            </Grid>
        </Grid>
    )

    const mobileView = () => (
        <Grid container xs={12} sx={{ display: { xs: 'block', sm: 'none' } }}>
            <PageTitle title={steps[activeStep].title} />
            {stepperContent()}
            <Grid item sx={{ m: 2 }}>
                {isResetButtonShown() &&
                    <Button onClick={handleReset} color={"error"} variant="outlined" fullWidth>
                        Reset
                    </Button>
                }
            </Grid>
            <MobileStepper
                variant="text"
                steps={steps.length}
                position="static"
                activeStep={activeStep}
                nextButton={
                    <Button
                        size="small"
                        disabled={isNextButtonDisabled[activeStep] || !isNextButtonShown()}
                        onClick={handleNext}
                    >
                        Next
                        <KeyboardArrowRightRoundedIcon />

                    </Button>
                }
                backButton={
                    <Button
                        size="small"
                        onClick={handleBack}
                        disabled={!isBackButtonShown()}
                    >
                        <KeyboardArrowLeftRoundedIcon />
                        Back
                    </Button>
                }
            />
        </Grid>
    )

    const stepperContent = () => (
        steps[activeStep].component
    )

    const nonMobileView = () => (
        <Grid container xs={12} sx={{ display: { xs: 'none', sm: 'block' } }}>
            <Stepper alternativeLabel activeStep={activeStep} connector={<ColorlibConnector />}>
                {steps.map((step) => (
                    <Step key={step.key}>
                        <StepLabel StepIconComponent={ColorlibStepIcon}>{step.title}</StepLabel>
                    </Step>
                ))}
            </Stepper>
            {stepperContent()}
            {renderButtons()}
        </Grid>
    )

    return (
        <Stack sx={{ width: '100%' }} spacing={4}>
            {mobileView()}
            {nonMobileView()}
        </Stack>
    );
}
