import { TextField, InputAdornment, Typography } from "@mui/material"
import { useDispatch } from "react-redux"
import { NumericFormat } from 'react-number-format'
import { LITERALS } from "../../utils/constants"

type SalaryComponentInputProps = {
    onInputChange: any,
    value: number,
    maxValue?: number,
    maxValueHint?: string
}

export const SalaryComponentInput = (props: SalaryComponentInputProps) => {

    const { onInputChange, value, maxValue, maxValueHint } = { ...props }
    const dispatch = useDispatch()

    const handleInputValueChange = (event: any) => {
        const inputValue = !event.floatValue ? 0 : event.floatValue
        dispatch(onInputChange(parseInt(inputValue)))
    }

    const endAdornmentMessage = () => {
        if (maxValue)
            return <>
                (max: <NumericFormat
                    displayType="text"
                    value={maxValue}
                    thousandSeparator={true}
                    thousandsGroupStyle={'lakh'}
                />)
            </>
        else if (maxValueHint)
            return `(max: ${maxValueHint})`
    }

    return (
        <NumericFormat
            customInput={TextField}
            onValueChange={handleInputValueChange}
            value={value}
            variant="outlined" size="small"
            fullWidth
            thousandSeparator={true}
            thousandsGroupStyle={'lakh'}
            InputProps={{
                startAdornment: <InputAdornment position="start">{LITERALS.INDIAN_RUPEE}</InputAdornment>,
                inputProps: { min: 0, max: maxValue ?? 10000000 },
                endAdornment: <Typography variant="caption">{endAdornmentMessage()}</Typography>
            }}
            allowNegative={false}
            fixedDecimalScale
            decimalScale={0}
        />
    )
}