import { InputAdornment, TextField, Typography } from "@mui/material"
import { NumericFormat } from "react-number-format"
import { LITERALS } from "../../utils/constants"

type SalaryComponentInputOutput = {
    outputValue: number,
    strikedValue?: number
}

export const SalaryComponentOutput = (props: SalaryComponentInputOutput) => {

    const { outputValue, strikedValue } = { ...props }

    return (    
        <NumericFormat
            customInput={TextField}
            value={outputValue}
            variant="outlined" size="small"
            fullWidth
            thousandSeparator={true}
            thousandsGroupStyle={'lakh'}
            InputProps={{
                startAdornment:
                    <InputAdornment position="start">
                        {LITERALS.INDIAN_RUPEE}
                        {strikedValue && <Typography sx={{ textDecoration: 'line-through' }}>{strikedValue}</Typography>}
                    </InputAdornment>
            }}
            allowNegative={false}
            fixedDecimalScale
            decimalScale={0}
            disabled
        />
    )
}